@app.after_request
def log_response_info(response):
    """
    Logs detailed information about the outgoing response.
    Includes request ID, status code, latency, and response body (masked if sensitive).
    """
    request_id = getattr(g, 'request_id', 'N/A')
    log_extra = {'request_id': request_id}
    elapsed_time = (time.time() - g.start_time) if hasattr(g, 'start_time') else 'N/A'

    response_body_to_log = None
    try:
        # Clone the response to read its data without consuming it for the client
        # WARNING: Reading large response bodies can be inefficient and consume memory.
        # Consider limiting the size of logged response bodies.
        if response.is_json:
            response_json = json.loads(response.data)
            # Mask sensitive data in response body if any (e.g., tokens, PII)
            if 'token' in response_json:
                response_json['token'] = '[MASKED]'
            if 'refresh_token' in response_json:
                response_json['refresh_token'] = '[MASKED]'
            response_body_to_log = response_json
        else:
            # Limit logging of non-JSON response bodies
            decoded_body = response.data.decode('utf-8', errors='ignore')
            response_body_to_log = decoded_body[:500] + '...' if len(decoded_body) > 500 else decoded_body
    except Exception as e:
        logger.warning(
            f"Could not parse response body for logging: {e}",
            extra=log_extra
        )
        response_body_to_log = f"Error parsing response body: {str(e)}"

    logger.info(
        f"Outgoing Response: Status={response.status_code}, "
        f"Latency={elapsed_time:.4f}s, "
        f"ResponseHeaders={json.dumps(dict(response.headers))}, "
        f"ResponseBody={json.dumps(response_body_to_log) if response_body_to_log else 'None'}",
        extra=log_extra
    )
    return response

