@app.errorhandler(Exception)
def handle_exception(e):
    """
    Global error handler to log all uncaught exceptions with their full traceback.
    Returns a generic error response to the client.
    """
    request_id = getattr(g, 'request_id', 'N/A')
    log_extra = {'request_id': request_id}

    # Log the full traceback for debugging errors
    logger.exception(
        f"An unhandled exception occurred during request processing.",
        extra=log_extra
    )

    # Return a generic error response to the client
    status_code = getattr(e, 'code', 500) # Get HTTP status code if available (e.g., for HTTPException)
    return jsonify({
        "error": "An internal server error occurred.",
        "request_id": request_id,
        "message": str(e) # Optional: Include error message for debugging (consider removing in production)
    }), status_code

